import React, { useCallback, useMemo } from 'react';
import { Button, Modal, dispatchAppToast, DocumentHistoryModal, getActiveCompanyCode, getCompanyBranding } from '@linm-soft-org/linm-web-common-components';
import { UnsavedChangesModal } from '../../../../../components/form';
import {
  VoucherSearchSlideout,
  ProcessingLevelApproveModal,
  VoucherPrintModal,
  VoucherPostedLedgerModal,
  ConfirmSaveVoucherModal,
} from '../../../../../components/voucher';
import { useAppDispatch } from '../../../../../store/hooks';
import { InvoiceAllocateSlideout } from '../../../../../components/kt/InvoiceAllocateSlideout';
import { LinkedInvoicesViewSlideout } from '../../../../../components/kt/LinkedInvoicesViewSlideout';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherFormModals: React.FC<{ vm: CashVoucherFormViewModel }> = ({ vm }) => {
  const dispatch = useAppDispatch();
  const onHistoryError = useCallback((message: string) => {
    dispatchAppToast(dispatch, { message, type: 'error' });
  }, [dispatch]);

  const {
    cfg,
    labels,
    kind,
    isNew,
    id,
    voucherNumber,
    voucherDate,
    customerName,
    customerType,
    voucherCompanyCode,
    totalAmount,
    processingLevel,
    processingOpts,
    showSearchSlideout,
    setShowSearchSlideout,
    handleOpenFromSearch,
    showApproveModal,
    setShowApproveModal,
    handleApproveConfirm,
    approving,
    showPrintModal,
    setShowPrintModal,
    showHistoryModal,
    setShowHistoryModal,
    handlePrintConfirm,
    printing,
    showAllocateModal,
    setShowAllocateModal,
    showLinkedInvoicesSlideout,
    setShowLinkedInvoicesSlideout,
    linkedInvoices,
    listPath,
    navigate,
    customerId,
    handleAllocateConfirm,
    showUnsavedModal,
    cancelLeave,
    confirmLeave,
    tid,
    showDeleteModal,
    setShowDeleteModal,
    handleDelete,
    deleting,
    showConfirmSaveModal,
    setShowConfirmSaveModal,
    handleConfirmSave,
    saving,
    showLedgerModal,
    setShowLedgerModal,
  } = vm;

  // ── Confirm-save helpers ──
  const customerTypeLabel = useMemo(() => {
    if (!customerType) return '';
    const map: Record<string, string> = {
      Customer: 'Khách hàng',
      Supplier: 'Nhà cung cấp',
      Both: 'Khách hàng & NCC',
      Employee: 'Nhân viên',
    };
    return map[customerType] ?? customerType;
  }, [customerType]);

  const companyBranding = useMemo(() => {
    try {
      return getCompanyBranding();
    } catch {
      return undefined;
    }
    // getCompanyBranding reads from cached storage (login root) — không recall load data
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const companyCode = useMemo(() => {
    const code = voucherCompanyCode ?? getActiveCompanyCode() ?? '';
    if (!code) return '';
    const branding = companyBranding;
    if (branding?.code === code && branding?.shortName) {
      return `${code} — ${branding.shortName}`;
    }
    return code;
  }, [voucherCompanyCode, companyBranding]);

  const voucherActionLabel = kind === 'receipt' ? 'thu' : 'chi';
  const noCustomerWarning = customerName?.trim()
    ? null
    : <span className={styles.confirmSaveWarning} data-testid={tid('confirm-save-customerName-empty')}>Phiếu {voucherActionLabel} không có đối tượng</span>;

  return (
    <>
      <VoucherSearchSlideout
        isOpen={showSearchSlideout}
        onClose={() => setShowSearchSlideout(false)}
        title={`Tìm ${labels.title.toLowerCase()}`}
        testIdPrefix={cfg.testIdPrefix}
        listScope={cfg.searchListScope}
        fetchList={cfg.fetch}
        onOpenVoucher={handleOpenFromSearch}
        processingLevelFilterOptions={processingOpts}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, processingOpts)}
      />

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={processingLevel}
        levelOptions={processingOpts}
        onConfirm={handleApproveConfirm}
        saving={approving}
        testIdPrefix={cfg.testIdPrefix}
      />

      <VoucherPrintModal
        isOpen={showPrintModal}
        onClose={() => setShowPrintModal(false)}
        voucherTitle={!isNew ? `${labels.title} — ${voucherNumber || '...'}` : undefined}
        onPrint={handlePrintConfirm}
        printing={printing}
        testIdPrefix={cfg.testIdPrefix}
      />

      {'documentHistoryType' in cfg && cfg.documentHistoryType && 'documentHistoryClient' in cfg && cfg.documentHistoryClient && id && (
        <DocumentHistoryModal
          isOpen={showHistoryModal}
          onClose={() => setShowHistoryModal(false)}
          client={cfg.documentHistoryClient}
          documentType={cfg.documentHistoryType}
          documentId={id}
          documentCode={voucherNumber || undefined}
          testIdPrefix={cfg.testIdPrefix}
          onError={onHistoryError}
        />
      )}

      <InvoiceAllocateSlideout
        isOpen={showAllocateModal}
        onClose={() => setShowAllocateModal(false)}
        customerId={customerId}
        voucherTotal={totalAmount}
        onConfirm={handleAllocateConfirm}
        testIdPrefix={cfg.testIdPrefix}
      />

      <LinkedInvoicesViewSlideout
        isOpen={showLinkedInvoicesSlideout}
        onClose={() => setShowLinkedInvoicesSlideout(false)}
        invoices={linkedInvoices}
        returnPath={listPath}
        returnTitle={labels.title}
        navigate={navigate}
        testIdPrefix={cfg.testIdPrefix}
      />

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={tid('unsaved-modal')}
      />

      <ConfirmSaveVoucherModal
        isOpen={showConfirmSaveModal}
        onClose={() => setShowConfirmSaveModal(false)}
        onConfirm={handleConfirmSave}
        saving={saving}
        testIdPrefix={cfg.testIdPrefix}
        fields={[
          { label: 'Ngày chứng từ', value: voucherDate, testId: tid('confirm-save-voucherDate') },
          { label: 'Đơn vị hoạch toán', value: companyCode, testId: tid('confirm-save-companyCode') },
          {
            label: 'Tổng tiền',
            value: new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(totalAmount),
            testId: tid('confirm-save-totalAmount'),
          },
          {
            label: 'Loại đối tượng',
            value: customerTypeLabel,
            testId: tid('confirm-save-customerType'),
            hidden: !customerName?.trim(),
          },
          {
            label: 'Tên đối tượng',
            value: customerName || noCustomerWarning,
            testId: tid('confirm-save-customerName'),
            fullWidth: true,
          },
        ]}
      />

      <Modal isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} title={`Xác nhận xóa ${labels.title.toLowerCase()}`}>
        <p>Bạn có chắc muốn xóa chứng từ này? Hành động không thể hoàn tác.</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>Hủy</Button>
          <Button variant="danger" onClick={handleDelete} loading={deleting}>Xóa</Button>
        </div>
      </Modal>

      {!isNew && id && (
        <VoucherPostedLedgerModal
          isOpen={showLedgerModal}
          onClose={() => setShowLedgerModal(false)}
          voucherTitle={`${labels.title} — ${voucherNumber || '...'}`}
          testIdPrefix={cfg.testIdPrefix}
          fetchPostedLedger={() => cfg.getPostedLedger(id)}
          fetchPostingStatus={() => cfg.getPostingStatus(id)}
        />
      )}
    </>
  );
};
