import { useCallback } from 'react';
import { dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import type { AppDispatch } from '../../../../../store/store';
import { serializeVoucherSnapshot, CASH_VOUCHER_CREATE_HYDRATE_KEY } from '../../../../../components/voucher';
import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';
import { getApiErrorMessage } from '../../../../../utils/getApiErrorMessage';
import type { CashVoucherDto, CashVoucherShellApiCode } from '../../../../../services/kt/models';
import type { CashVoucherConfig } from '../config/cashVoucherConfig';
import { buildSnapshotFromState, mapFormStateToPayload } from '../mappers/cashVoucherMappers';
import type { CashVoucherFormAction, CashVoucherFormReducerState } from '../types/cashVoucherFormState.types';

function readCreatedVoucherCode(created: CashVoucherDto): string {
  return (created.code ?? '').trim();
}

export function useCashVoucherSubmit(params: {
  kind: CashVoucherKind;
  cfg: CashVoucherConfig;
  state: CashVoucherFormReducerState;
  dispatch: React.Dispatch<CashVoucherFormAction>;
  isNew: boolean;
  id?: string;
  showInvoiceGrid: boolean;
  showDetailObject: boolean;
  totalAmount: number;
  voucherShell?: CashVoucherShellApiCode | null;
  detailPath: (id: string) => string;
  saveSuccessLabel: string;
  navigate: (path: string, options?: { state?: Record<string, unknown> }) => void;
  appDispatch: AppDispatch;
  defaultProcessingLevel?: string;
  onSaveSuccessNew: (createdId: string, code: string) => void;
  onSaveSuccessUpdate: (updated: CashVoucherDto) => void;
}) {
  const {
    kind, cfg, state, dispatch, isNew, id, showInvoiceGrid, showDetailObject, totalAmount, voucherShell,
    detailPath, saveSuccessLabel, navigate, appDispatch, defaultProcessingLevel, onSaveSuccessNew, onSaveSuccessUpdate,
  } = params;

  const save = useCallback(async () => {
    const payload = mapFormStateToPayload(state, cfg, kind, { showInvoiceGrid, showDetailObject, totalAmount, voucherShell, defaultProcessingLevel });
    if (isNew) {
      const created = await cfg.create(payload);
      const code = readCreatedVoucherCode(created);
      if (!created.id?.trim() || !code) {
        throw new Error('Lưu thành công nhưng không nhận được số chứng từ từ máy chủ.');
      }
      dispatch({ type: 'SET_HEADER', key: 'voucherNumber', value: code });
      dispatchAppToast(appDispatch, { message: saveSuccessLabel, type: 'success' });
      const snap = serializeVoucherSnapshot(
        buildSnapshotFromState(state, { showInvoiceGrid, defaultProcessingLevel }),
      );
      dispatch({ type: 'SET_META', patch: { savedSnapshot: snap } });
      dispatch({ type: 'COMMIT_INITIAL' });
      onSaveSuccessNew(created.id, code);
      navigate(detailPath(created.id), {
        state: { [CASH_VOUCHER_CREATE_HYDRATE_KEY]: created },
      });
    } else {
      const updated = await cfg.update(id!, payload);
      dispatchAppToast(appDispatch, { message: 'Cập nhật thành công', type: 'success' });
      onSaveSuccessUpdate(updated);
    }
  }, [
    state, cfg, kind, showInvoiceGrid, showDetailObject, totalAmount, voucherShell, defaultProcessingLevel, isNew, id,
    detailPath, saveSuccessLabel, navigate, appDispatch, onSaveSuccessNew, onSaveSuccessUpdate, dispatch,
  ]);

  const saveWithErrorToast = useCallback(async (): Promise<boolean> => {
    try {
      await save();
      return true;
    } catch (e: unknown) {
      dispatchAppToast(appDispatch, {
        message: getApiErrorMessage(e, 'Lưu thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
      return false;
    }
  }, [save, appDispatch]);

  return { save, saveWithErrorToast };
}
